    def __init__(self, x):
        self.val = x
        self.left = None
        self.right = None

def can_win(root, x):
    if not root:
        return False
    if root.val == x:
        left_nodes = 1 + can_win(root.left, x) if root.left else 0
        right_nodes = 1 + can_win(root.right, x) if root.right else 0
        return left_nodes % 2 != 0 or right_nodes % 2 != 0
    return can_win(root.left, x) or can_win(root.right, x)
